examples.code:
#include <vector>
#include <iostream>
using namespace std;

vector<int> v = {10, 20, 30};
v.push_back(40);
v.push_back(50);

cout << v.size() << endl;   // 5
cout << v[0] << endl;       // 10 (unchecked)
cout << v.at(2) << endl;    // 30 (throws if OOB)

v.pop_back();               // removes 50

for (const auto& x : v) cout << x << " ";
// 10 20 30 40

// C++ vector (recommended — dynamic, safe):
vector<int> v;
v.push_back(1);

// C-style array (fixed, no bounds check):
int arr[5] = {1,2,3,4,5};

// std::array (C++11, fixed size but safe):
#include <array>
array<int,5> a = {1,2,3,4,5};
cout << a.size() << endl;  // 5
cout << a.at(2) << endl;  // 3 (bounds checked)

#include <array>
using namespace std;

array<int, 5> arr = {1, 2, 3, 4, 5};

cout << arr.size() << endl;   // 5
cout << arr.front() << endl;  // 1
cout << arr.back() << endl;   // 5

for (auto x : arr) cout << x << " ";
// 1 2 3 4 5

// Bounds-checked access:
try {
    arr.at(10);  // throws std::out_of_range
} catch (...) {
    cout << "Out of bounds!" << endl;
}

