#include <map>
#include <unordered_map>
using namespace std;

// map: sorted keys
map<string,int> scores;
scores["Alice"] = 95;
scores["Bob"] = 87;
// Iterates in alphabetical key order!
for (auto& [k,v] : scores)
    cout << k << ": " << v << endl;

// unordered_map: O(1) lookup
unordered_map<string,int> fast;
fast["Alice"] = 95;
cout << fast["Alice"] << endl; // 95
cout << fast.count("Alice"); // 1 (exists)

